// beliq: parse returns the document as a structured invoice on the item JSON.
// Pull out the fields your downstream step needs; optional chaining keeps this
// robust if a field is absent on a given document.
const inv = $json;
return [{ json: {
  invoiceNumber: inv.number,
  currency: inv.currencyCode,
  sellerName: inv.seller?.name,
  buyerName: inv.buyer?.name,
  lineCount: inv.lines?.length,
  totalGross: inv.totalGrossAmount,
} }];
